+        let after_second = app.event_log.len();
+
+        assert_eq!(after_first, initial_events + 1);
+        assert_eq!(after_second, after_first);
+        assert!(app.paused);
+        assert_eq!(app.last_autopause_tick, Some(app.snapshot.tick));
+    }
